mapper.select:
select count(id)
from tbl_estimation
where receiver_id = #{receiverId}

select count(id)
from tbl_estimation
where requester_id = #{requesterId}

select m.id, m.member_name as memberName, m.member_nickname as memberNickname, m.member_handle as memberHandle, m.member_email as memberEmail, ( select f.file_name from tbl_member_profile_file mpf join tbl_file f on mpf.id = f.id where mpf.member_id = m.id and mpf.profile_image_type = 'profile' limit 1 ) as memberProfileFileName from tbl_member m where m.member_role = 'expert' and m.member_status = 'active' and m.id != #{memberId}
and ( lower(m.member_name) like lower(concat('%', #{keyword}, '%')) or lower(coalesce(m.member_nickname, '')) like lower(concat('%', #{keyword}, '%')) or lower(coalesce(m.member_handle, '')) like lower(concat('%', #{keyword}, '%')) or lower(m.member_email) like lower(concat('%', #{keyword}, '%')) )
order by m.created_datetime desc limit 20
